(function(){
  function noop() {}

  function trigger(inst, eventName, args) {
    var handlers = inst._handlers[eventName] || [];
    for (var i = 0; i < handlers.length; i++) {
      handlers[i].apply(inst, args || []);
    }
  }

  function formatSize(bytes) {
    if (bytes < 1024) {
      return bytes + ' B';
    }
    if (bytes < 1024 * 1024) {
      return (bytes / 1024).toFixed(1) + ' KB';
    }
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  }

  function removeFile(inst, file) {
    var index = inst._queue.indexOf(file);
    if (index !== -1) {
      inst._queue.splice(index, 1);
    }
    if (file._dzPreview && file._dzPreview.parentNode) {
      file._dzPreview.parentNode.removeChild(file._dzPreview);
    }
    var remaining = inst.element.querySelectorAll('.dz-preview');
    var message = inst.element.querySelector('.dz-message');
    if (message && remaining.length === 0) {
      message.style.display = '';
    }
    trigger(inst, 'removedfile', [file]);
  }

  function renderPreview(inst, file) {
    var preview = document.createElement('div');
    preview.className = 'dz-preview dz-file-preview';

    var image = document.createElement('div');
    image.className = 'dz-image';
    var placeholder = document.createElement('span');
    placeholder.className = 'dz-file-icon';
    placeholder.textContent = (file.name.split('.').pop() || 'FILE').substring(0, 5).toUpperCase();
    image.appendChild(placeholder);

    var details = document.createElement('div');
    details.className = 'dz-details';
    var filename = document.createElement('div');
    filename.className = 'dz-filename';
    filename.title = file.name;
    filename.textContent = file.name;
    var size = document.createElement('div');
    size.className = 'dz-size';
    size.textContent = formatSize(file.size || 0);
    details.appendChild(filename);
    details.appendChild(size);

    var remove = document.createElement('a');
    remove.className = 'dz-remove';
    remove.href = '#';
    remove.textContent = 'Remove file';
    remove.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      removeFile(inst, file);
    });

    preview.appendChild(image);
    preview.appendChild(details);
    if (inst.options.addRemoveLinks !== false) {
      preview.appendChild(remove);
    }
    file._dzPreview = preview;
    inst.element.appendChild(preview);

    var message = inst.element.querySelector('.dz-message');
    if (message) {
      message.style.display = 'none';
    }

    if (inst.options.createImageThumbnails !== false &&
        file.type && file.type.indexOf('image/') === 0 &&
        window.URL && window.URL.createObjectURL) {
      var img = document.createElement('img');
      var objectUrl = window.URL.createObjectURL(file);
      img.alt = file.name;
      img.onload = function() {
        window.URL.revokeObjectURL(objectUrl);
        preview.className += ' dz-image-preview';
        trigger(inst, 'thumbnail', [file, objectUrl]);
      };
      img.src = objectUrl;
      image.innerHTML = '';
      image.appendChild(img);
    }
  }

  function enqueueFile(inst, file) {
    inst._queue.push(file);
    renderPreview(inst, file);
    trigger(inst, 'addedfile', [file]);
  }

  function createHiddenInput(inst) {
    var input = document.createElement('input');
    input.type = 'file';
    input.multiple = true;
    input.style.display = 'none';
    input.addEventListener('change', function() {
      if (input.files && input.files.length) {
        for (var i = 0; i < input.files.length; i++) {
          enqueueFile(inst, input.files[i]);
        }
      }
      input.value = '';
    });
    return input;
  }

  function getXHRError(xhr) {
    if (!xhr) {
      return 'Upload failed';
    }
    if (xhr.responseText) {
      return xhr.responseText;
    }
    return 'HTTP ' + xhr.status;
  }

  function sendFile(inst, file, done) {
    var xhr = new XMLHttpRequest();
    var formData = new FormData();
    var paramName = inst.options.paramName || 'file';

    file.upload = file.upload || {};
    if (!file.upload.uuid) {
      file.upload.uuid = 'xxxxxxxxxxxx4xxxyxxxxxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0;
        var v = c === 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
      });
    }

    formData.append(paramName, file, file.name);
    trigger(inst, 'sending', [file, xhr, formData]);

    xhr.onreadystatechange = function() {
      if (xhr.readyState !== 4) {
        return;
      }
      if (xhr.status >= 200 && xhr.status < 300) {
        if (file._dzPreview) {
          file._dzPreview.className += ' dz-success';
        }
        trigger(inst, 'success', [file, xhr.responseText, xhr]);
      } else {
        if (file._dzPreview) {
          file._dzPreview.className += ' dz-error';
        }
        trigger(inst, 'error', [file, getXHRError(xhr), xhr]);
      }
      done();
    };

    xhr.open('POST', inst.options.url || inst.element.getAttribute('action') || window.location.href, true);
    xhr.send(formData);
  }

  function processNext(inst) {
    if (inst._active >= inst.options.parallelUploads || inst._queue.length === 0) {
      if (inst._active === 0 && inst._queue.length === 0) {
        trigger(inst, 'queuecomplete', []);
      }
      return;
    }

    var file = inst._queue.shift();
    inst._active++;
    sendFile(inst, file, function() {
      inst._active--;
      processNext(inst);
      if (inst._queue.length > 0 && inst._active < inst.options.parallelUploads) {
        processNext(inst);
      }
    });

    if (inst._active < inst.options.parallelUploads && inst._queue.length > 0) {
      processNext(inst);
    }
  }

  function setupDragDrop(inst) {
    function prevent(e) {
      e.preventDefault();
      e.stopPropagation();
    }

    inst.element.addEventListener('dragover', prevent);
    inst.element.addEventListener('dragenter', prevent);
    inst.element.addEventListener('drop', function(e) {
      prevent(e);
      var files = (e.dataTransfer && e.dataTransfer.files) ? e.dataTransfer.files : [];
      for (var i = 0; i < files.length; i++) {
        enqueueFile(inst, files[i]);
      }
      if (inst.options.autoProcessQueue !== false) {
        inst.processQueue();
      }
    });

    inst.element.addEventListener('click', function() {
      inst._input.click();
    });
  }

  function Dropzone(selector, options) {
    if (!(this instanceof Dropzone)) {
      return new Dropzone(selector, options);
    }

    this.element = typeof selector === 'string' ? document.querySelector(selector) : selector;
    if (!this.element) {
      throw new Error('Dropzone element not found: ' + selector);
    }

    this.options = options || {};
    if (typeof this.options.parallelUploads !== 'number' || this.options.parallelUploads < 1) {
      this.options.parallelUploads = 1;
    }

    this._handlers = {};
    this._queue = [];
    this._active = 0;

    this._input = createHiddenInput(this);
    this.element.appendChild(this._input);

    var self = this;
    this._input.addEventListener('change', function() {
      if (self.options.autoProcessQueue !== false) {
        self.processQueue();
      }
    });

    setupDragDrop(this);
  }

  Dropzone.prototype.on = function(eventName, handler) {
    if (!this._handlers[eventName]) {
      this._handlers[eventName] = [];
    }
    this._handlers[eventName].push(typeof handler === 'function' ? handler : noop);
    return this;
  };

  Dropzone.prototype.getQueuedFiles = function() {
    return this._queue.slice();
  };

  Dropzone.prototype.processQueue = function() {
    processNext(this);
  };

  Dropzone.autoDiscover = false;
  window.Dropzone = Dropzone;
})();
